   102→	async load<T extends SomeEntity>(typeRef: TypeRef<T>, id: T["_id"], queryParameters: Dict | null | undefined, extraHeaders?: Dict): Promise<T> {
   103→		if (id instanceof Array && id.length === 2) {
   104→			// list element request
   105→			const listId = id[0]
   106→			const elementId = id[1]
   107→
   108→			const listElement = this._getListEntry(listId, elementId)
   109→
   110→			if (listElement == null) throw new NotFoundError(`List element ${listId} ${elementId} not found`)
   111→			return downcast(listElement)
   112→		} else if (typeof id === "string") {
   113→			//element request
   114→			return this._handleMockElement(this._entities[id], id)
   115→		} else {
   116→			throw new Error("Illegal Id for ET: " + (id as any))
   117→		}
   118→	}
   119→
   120→	async loadRange<T extends ListElementEntity>(typeRef: TypeRef<T>, listId: Id, start: Id, count: number, reverse: boolean): Promise<T[]> {
   121→		let entriesForListId = this._listEntities[listId]
   122→		if (!entriesForListId) return []
   123→		let filteredIds
   124→
   125→		if (reverse) {
   126→			filteredIds = Object.keys(entriesForListId)
   127→				.sort(compareNewestFirst)
   128→				.filter((id) => firstBiggerThanSecond(start, id))
   129→		} else {
   130→			filteredIds = Object.keys(entriesForListId)
   131→				.sort(compareOldestFirst)
   132→				.filter((id) => firstBiggerThanSecond(id, start))
   133→		}
   134→
   135→		return filteredIds.map((id) => this._handleMockElement(entriesForListId[id], id))
   136→	}
   137→
   138→	async loadMultiple<T extends SomeEntity>(typeRef: TypeRef<T>, listId: Id | null | undefined, elementIds: Array<Id>): Promise<Array<T>> {
   139→		const lid = listId
   140→
   141→		if (lid) {
   142→			const typeModule = await resolveTypeReference(typeRef)
   143→			if (typeModule.type === Type.ListElement.valueOf()) {
   144→				return elementIds
   145→					.map((id) => {
   146→						return downcast(this._getListEntry(lid, id))
   147→					})
   148→					.filter(Boolean)
   149→			} else {
   150→				return elementIds
   151→					.map((id) => {
   152→						return downcast(this._getBlobEntry(lid, id))
   153→					})
   154→					.filter(Boolean)
   155→			}
   156→		} else {
   157→			return elementIds
