   173→	erase<T extends SomeEntity>(instance: T): Promise<void> {
   174→		return resolveTypeReference(instance._type).then((typeModel) => {
   175→			_verifyType(typeModel)
   176→
   177→			var ids = getIds(instance, typeModel)
   178→
   179→			this._handleDelete(ids.id, ids.listId)
