   195→	_handleDelete(id: Id | null | undefined, listId: Id | null | undefined) {
   196→		if (id && listId) {
   197→			if (this._getListEntry(listId, id)) {
   198→				delete this._listEntities[listId][id]
   199→			} else {
   200→				throw new NotFoundError(`List element ${listId} ${id} not found`)
   201→			}
   202→		} else if (id) {
