		// Verify the method signature - it should only accept typeRef, listId, and elementIds
		// The TypeScript interface doesn't include ownerKey
		const methodSignature = Object.getOwnPropertyNames(Object.getPrototypeOf(entityClient))
		expect(methodSignature).toContain("loadMultiple")

		// We can call it with 3 arguments only
		try {
			// Mock returns empty array, so this should not throw
			const result = await entityClient.loadMultiple(typeRef, listId, elementIds)
			expect(Array.isArray(result)).toBe(true)
		} catch (e) {
			// Expected if the REST client doesn't have mock data
			// The test is about the API signature, not the mock implementation
		}
	})

