		})

		// Both mails have owner-encrypted session keys
		o(mail1._ownerEncSessionKey).notEquals(null)
		o(mail2._ownerEncSessionKey).notEquals(null)
		o(mail1._ownerEncSessionKey).notEquals(mail2._ownerEncSessionKey)

		// The problem: when loading the related mail details blobs for both mails,
