					name: "Recipient Name",
				}),
			],
			ccRecipients: [],
			bccRecipients: [],
			replyTos: [],
			attachments: [],
			mailDetails: ["mailDetailsBlobListId", "mailDetailsBlobId"],
			headers: null,
			body: null,
			conversationEntry: ["conversationListId", "conversationId"],
			previousMail: null,
			nextMail: null,
			bcc: false,
			unread: false,
			answered: false,
			redirected: false,
			sentDate: new Date().getTime(),
