			_ownerGroup: "ownerGroupId",
			details: createMailDetails({
				sentDate: new Date().getTime(),
				replyTos: [],
				recipients: {
					toRecipients: [
						createMailAddress({
							address: "recipient@example.com",
							name: "Recipient Name",
						}),
					],
					ccRecipients: [],
					bccRecipients: [],
				},
				headers: null,
				text: "This is the mail body content",
				inlineImages: [],
				attachments: [],
				compressedText: null,
			}),
		})

