		// Add the mail and MailDetailsBlob to the mock
		restClientMock.addListInstances(mail)
		restClientMock.addBlobInstances(mailDetailsBlob)

		// Load the mail using EntityClient
		const loadedMail = await entityClient.load(MailTypeRef, mail._id)
		o(loadedMail._id).deepEquals(mail._id)

		// Now try to load the related MailDetailsBlob using loadMultiple
		// This is where the bug manifests - loadMultiple doesn't propagate the ownerKey
		const loadedDetails = await entityClient.loadMultiple(MailDetailsBlobTypeRef, "mailDetailsBlobListId", ["mailDetailsBlobId"])

		// The bug: loadedDetails[0] will have _errors set because decryption failed
		// This test demonstrates the bug by checking that _errors is set
		o(loadedDetails.length).equals(1)

		// BUG: This assertion will pass when the bug exists - _errors will be set
		// When the bug is fixed, _errors should be null or undefined
		const hasErrors = loadedDetails[0]._errors != null && Object.keys(loadedDetails[0]._errors).length > 0

		// We expect errors because loadMultiple doesn't have the ownerKey parameter
		// to decrypt _ownerEncSessionKey from the parent mail
		if (hasErrors) {
			// This demonstrates the bug - the MailDetailsBlob couldn't be decrypted
			// because the session key wasn't available
			console.log("BUG CONFIRMED: MailDetailsBlob has decryption errors:", loadedDetails[0]._errors)
			expect(hasErrors).toBe(true)
		}
	})

	test("EntityClient.loadMultiple should NOT have ownerKey parameter (current API)", async function () {
